import React from "react";
import { Link, useNavigate } from "react-router-dom";

const NavBar = () => {
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem("role");
    navigate("/");
  };

  return (
    <nav
      style={{
        backgroundColor: "#a71010",
        padding: "12px 30px",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        color: "#fff",
        borderRadius: "6px 6px 0 0",
        marginBottom: "25px",
      }}
    >
      <div style={{ fontWeight: "700", fontSize: "1.2rem" }}>NexaLearn LMS</div>
      <div style={{ display: "flex", gap: "20px", alignItems: "center" }}>
        <Link to="/admin" style={{ color: "#fff", textDecoration: "none" }}>
          Admin
        </Link>
        <Link to="/instructor" style={{ color: "#fff", textDecoration: "none" }}>
          Instructor
        </Link>
        <Link to="/student" style={{ color: "#fff", textDecoration: "none" }}>
          Student
        </Link>
        <Link to="/content" style={{ color: "#fff", textDecoration: "none" }}>
          Content Creator
        </Link>
        <button
          onClick={handleLogout}
          style={{
            backgroundColor: "#800000",
            border: "none",
            color: "#fff",
            cursor: "pointer",
            padding: "6px 12px",
            borderRadius: "4px",
            fontWeight: "600",
          }}
        >
          Logout
        </button>
      </div>
    </nav>
  );
};

export default NavBar;
